            // Solo si no hay tema guardado, verificar preferencia del sistema
            const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
            if (prefersDark) {
                html.classList.add('dark');
                document.body.classList.add('dark');
            }
        }
    })();

    // Configuración completa después de cargar
    document.addEventListener('DOMContentLoaded', () => {
        const wrapper = document.getElementById('imperiodev-wrapper');
        const html = document.documentElement;
        const btnDark = document.getElementById('btn-dark');
        const btnLight = document.getElementById('btn-light');

        function applyTheme(theme) {
            // Deshabilitar transiciones durante cambio
            html.style.transition = 'none';
            document.body.style.transition = 'none';
            
            if (theme === 'dark') {
                html.classList.add('dark');
                document.body.classList.add('dark');
                if(wrapper) wrapper.classList.add('dark');
                if(btnDark) btnDark.classList.add('active');
                if(btnLight) btnLight.classList.remove('active');
            } else {
                html.classList.remove('dark');
                document.body.classList.remove('dark');
                if(wrapper) wrapper.classList.remove('dark');
                if(btnLight) btnLight.classList.add('active');
                if(btnDark) btnDark.classList.remove('active');
            }
            
            // Restaurar transiciones
            void html.offsetWidth; // Forzar reflow
            html.style.transition = '';
            document.body.style.transition = '';
            
            localStorage.setItem('theme', theme);
        }

        window.setTheme = function(theme) {
