            lights.innerHTML = `
                <div class="ambient-light" style="top: 20%; left: 20%; width: 400px; height: 400px; background: rgba(20, 184, 166, 0.1);"></div>
                <div class="ambient-light" style="bottom: 20%; right: 20%; width: 300px; height: 300px; background: rgba(59, 130, 246, 0.1);"></div>
            `;
            document.body.prepend(lights);
            
            // Envolver el formulario existente en nuestro Glass Panel
            const loginDiv = document.getElementById('login');
            const form = document.getElementById('loginform');
            
            // Crear estructura del robot
            const robotHTML = `
                <div class="chatbot-container" id="robot-container">
                    <div class="chatbot" id="robot">
                        <div class="shell"></div>
                        <div class="arc-top"></div>
                        <div class="arc-bottom"></div>
                        <div class="ear left"></div>
                        <div class="ear right"></div>
                        <div class="head">
                            <div class="eye left" id="eye-left"></div>
                            <div class="eye right" id="eye-right"></div>
                            <div class="mouth"></div>
                        </div>
                        <div class="music-note">♪</div>
                    </div>
                </div>
            `;
            
            // Crear título
            const titleHTML = `
                <div class="login-brand">
                    <h1>IMPERIO<span>DEV</span></h1>
                    <p>Bienvenido de nuevo</p>
                </div>
            `;
            
            // Crear Glass Panel wrapper
            const glassPanel = document.createElement('div');
            glassPanel.className = 'glass-panel';
            
            // Insertar robot ANTES del glass panel
            const robotDiv = document.createElement('div');
            robotDiv.innerHTML = robotHTML;
            loginDiv.insertBefore(robotDiv.firstElementChild, loginDiv.firstChild);

            // Mover título y formulario DENTRO del glass panel
            glassPanel.innerHTML = titleHTML;
            
            // Mover mensajes de error si existen
            const messages = document.querySelectorAll('.message, .notice, #login_error');
            messages.forEach(msg => glassPanel.appendChild(msg));
            
            if(form) glassPanel.appendChild(form);
            
            loginDiv.insertBefore(glassPanel, loginDiv.querySelector('#nav')); 

            // --- LÓGICA DE INTERACCIÓN DEL ROBOT ---
            const robotContainer = document.getElementById('robot-container');
            const eyeLeft = document.getElementById('eye-left');
            const eyeRight = document.getElementById('eye-right');
            const passwordInput = document.querySelector('input[type="password"]');

            // 1. Seguimiento de Ojos
            function moveEyes(x, y) {
                if (robotContainer.classList.contains('shy')) return;

                const rect = robotContainer.getBoundingClientRect();
                const centerX = rect.left + (rect.width / 2);
                const centerY = rect.top + 80; 

                const angle = Math.atan2(y - centerY, x - centerX);
                const maxDist = 8; 
                const distance = Math.min(maxDist, Math.hypot(x - centerX, y - centerY) / 15); 

                const moveX = Math.cos(angle) * distance;
                const moveY = Math.sin(angle) * distance;

                if(eyeLeft && eyeRight) {
                    eyeLeft.style.transform = 'translate(' + moveX + 'px, ' + moveY + 'px)';
                    eyeRight.style.transform = 'translate(' + moveX + 'px, ' + moveY + 'px)';
                }
            }

            document.addEventListener('mousemove', (e) => moveEyes(e.clientX, e.clientY));
            document.addEventListener('touchmove', (e) => {
                if(e.touches.length > 0) moveEyes(e.touches[0].clientX, e.touches[0].clientY);
            });

            // 2. Modo Tímido
            if(passwordInput) {
                passwordInput.addEventListener('focus', () => {
                    robotContainer.classList.add('shy');
                    if(eyeLeft) eyeLeft.style.transform = '';
                    if(eyeRight) eyeRight.style.transform = '';
                });

                passwordInput.addEventListener('blur', () => {
                    robotContainer.classList.remove('shy');
                });
            }
        });
