    <script>
        window.toggleThemeGlobal = function() {
            const html = document.documentElement;
            if (html.classList.contains('dark')) {
                html.classList.remove('dark');
                localStorage.setItem('theme-id', 'light');
            } else {
                html.classList.add('dark');
                localStorage.setItem('theme-id', 'dark');
            }
        };

        window.toggleIDMenu = function() {
            const menu = document.getElementById('mobile-menu-id');
            if (menu.classList.contains('hidden')) {
                menu.classList.remove('hidden');
                setTimeout(() => menu.classList.remove('translate-x-full'), 10);
                document.body.style.overflow = 'hidden';
            } else {
                menu.classList.add('translate-x-full');
                setTimeout(() => menu.classList.add('hidden'), 300);
                document.body.style.overflow = '';
            }
        };

        document.addEventListener('DOMContentLoaded', () => {
            const openBtn = document.getElementById('id-open-menu');
            const closeBtn = document.getElementById('id-close-menu');
            if(openBtn) openBtn.addEventListener('click', toggleIDMenu);
            if(closeBtn) closeBtn.addEventListener('click', toggleIDMenu);

            window.addEventListener('scroll', () => {
                const nav = document.getElementById('navbar-id');
                if (window.scrollY > 20) {
                    nav.classList.add('shadow-lg', 'py-3');
                    nav.classList.remove('py-4');
                } else {
                    nav.classList.remove('shadow-lg', 'py-3');
                    nav.classList.add('py-4');
                }
            });
        });
    </script>
